import base64
import pickle
import json
from datetime import datetime
from typing import Any, Dict, List
import logging

logging.basicConfig(level=logging.INFO)
logger = logging.getLogger(__name__)


def process_task(task_data: Dict[str, Any]) -> Dict[str, Any]:
    """Process individual task based on task type"""
    task_type = task_data.get('type', 'unknown')
    
    if task_type == 'data_processing':
        return process_data_task(task_data)
    elif task_type == 'computation':
        return process_computation_task(task_data)
    elif task_type == 'aggregation':
        return process_aggregation_task(task_data)
    else:
        return {'status': 'error', 'message': f'Unknown task type: {task_type}'}


def process_data_task(task_data: Dict[str, Any]) -> Dict[str, Any]:
    """Process data transformation tasks"""
    data = task_data.get('data', [])
    operation = task_data.get('operation', 'identity')
    
    if operation == 'sum':
        result = sum(data) if isinstance(data, list) else 0
    elif operation == 'average':
        result = sum(data) / len(data) if isinstance(data, list) and len(data) > 0 else 0
    elif operation == 'transform':
        transform_fn = task_data.get('transform_function')
        result = [transform_fn(item) if callable(transform_fn) else item for item in data]
    else:
        result = data
    
    return {
        'status': 'success',
        'task_type': 'data_processing',
        'operation': operation,
        'result': result,
        'processed_count': len(data) if isinstance(data, list) else 1
    }


def process_computation_task(task_data: Dict[str, Any]) -> Dict[str, Any]:
    """Process computational tasks"""
    params = task_data.get('parameters', {})
    computation_type = task_data.get('computation', 'default')
    
    if computation_type == 'matrix_multiply':
        matrix_a = params.get('matrix_a', [])
        matrix_b = params.get('matrix_b', [])
        result = matrix_multiply(matrix_a, matrix_b)
    elif computation_type == 'statistical_analysis':
        dataset = params.get('dataset', [])
        result = statistical_analysis(dataset)
    else:
        result = params
    
    return {
        'status': 'success',
        'task_type': 'computation',
        'computation': computation_type,
        'result': result
    }


def process_aggregation_task(task_data: Dict[str, Any]) -> Dict[str, Any]:
    """Process data aggregation tasks"""
    datasets = task_data.get('datasets', [])
    aggregation_method = task_data.get('method', 'concat')
    
    if aggregation_method == 'concat':
        result = []
        for dataset in datasets:
            if isinstance(dataset, list):
                result.extend(dataset)
    elif aggregation_method == 'merge':
        result = {}
        for dataset in datasets:
            if isinstance(dataset, dict):
                result.update(dataset)
    else:
        result = datasets
    
    return {
        'status': 'success',
        'task_type': 'aggregation',
        'method': aggregation_method,
        'result': result,
        'datasets_processed': len(datasets)
    }


def matrix_multiply(matrix_a: List[List[float]], matrix_b: List[List[float]]) -> List[List[float]]:
    """Simple matrix multiplication"""
    if not matrix_a or not matrix_b:
        return []
    
    rows_a = len(matrix_a)
    cols_a = len(matrix_a[0]) if matrix_a else 0
    cols_b = len(matrix_b[0]) if matrix_b else 0
    
    if cols_a != len(matrix_b):
        return []
    
    result = [[0 for _ in range(cols_b)] for _ in range(rows_a)]
    
    for i in range(rows_a):
        for j in range(cols_b):
            for k in range(cols_a):
                result[i][j] += matrix_a[i][k] * matrix_b[k][j]
    
    return result


def statistical_analysis(dataset: List[float]) -> Dict[str, float]:
    """Perform basic statistical analysis"""
    if not dataset:
        return {}
    
    sorted_data = sorted(dataset)
    n = len(dataset)
    
    mean = sum(dataset) / n
    variance = sum((x - mean) ** 2 for x in dataset) / n
    std_dev = variance ** 0.5
    
    median = sorted_data[n // 2] if n % 2 == 1 else (sorted_data[n // 2 - 1] + sorted_data[n // 2]) / 2
    
    return {
        'mean': mean,
        'median': median,
        'std_dev': std_dev,
        'min': sorted_data[0],
        'max': sorted_data[-1],
        'count': n
    }


def process_batch_job(batch_data: Dict[str, Any]) -> Dict[str, Any]:
    """Process a batch job containing multiple tasks"""
    batch_id = batch_data.get('batch_id', 'unknown')
    tasks = batch_data.get('tasks', [])
    
    results = []
    successful = 0
    failed = 0
    
    for idx, task in enumerate(tasks):
        try:
            result = process_task(task)
            result['task_index'] = idx
            results.append(result)
            
            if result.get('status') == 'success':
                successful += 1
            else:
                failed += 1
        except Exception as e:
            logger.error(f"Error processing task {idx} in batch {batch_id}: {str(e)}")
            results.append({
                'task_index': idx,
                'status': 'error',
                'error': str(e)
            })
            failed += 1
    
    return {
        'batch_id': batch_id,
        'total_tasks': len(tasks),
        'successful': successful,
        'failed': failed,
        'results': results,
        'processed_at': datetime.utcnow().isoformat()
    }


def pubsub_processor(event, context):
    """Cloud Function entry point for Pub/Sub messages"""
    try:
        if 'data' not in event:
            logger.error("No data field in Pub/Sub message")
            return
        
        message_data = base64.b64decode(event['data'])
        
        deserialized_data = pickle.loads(message_data)
        
        logger.info(f"Received message: {type(deserialized_data)}")
        
        if isinstance(deserialized_data, dict):
            if 'batch_id' in deserialized_data or 'tasks' in deserialized_data:
                result = process_batch_job(deserialized_data)
            else:
                result = process_task(deserialized_data)
        elif isinstance(deserialized_data, list):
            batch_data = {'batch_id': 'auto', 'tasks': deserialized_data}
            result = process_batch_job(batch_data)
        else:
            result = {
                'status': 'error',
                'message': f'Unsupported data type: {type(deserialized_data)}'
            }
        
        logger.info(f"Processing result: {json.dumps(result, default=str)}")
        
        return result
        
    except pickle.UnpicklingError as e:
        logger.error(f"Failed to deserialize message: {str(e)}")
        return {'status': 'error', 'message': f'Deserialization failed: {str(e)}'}
    except Exception as e:
        logger.error(f"Error processing message: {str(e)}")
        return {'status': 'error', 'message': str(e)}